// 1. Sadə Mapped Type
type Person = { name: string; age: number };
type ReadonlyPerson = { readonly [P in keyof Person]: Person[P] };
const person: ReadonlyPerson = { name: "Alice", age: 30 };
// person.name = "Bob"; // Səhv: name yalnız oxuna biləndir
console.log(person); // Çıxış: { name: "Alice", age: 30 }

// 2. Mapped Type ilə Opsional Xüsusiyyətlər
type OptionalPerson = { [P in keyof Person]?: Person[P] };
const optionalPerson: OptionalPerson = { name: "Bob" }; // age opsionaldır
console.log(optionalPerson); // Çıxış: { name: "Bob" }

// 3. Şərti Tiplərlə Mapped Type
type StringOnly<T> = { [P in keyof T]: T[P] extends string ? T[P] : never };
type StringPerson = StringOnly<Person>;
const stringPerson: StringPerson = { name: "Alice", age: null };
console.log(stringPerson); // Çıxış: { name: "Alice", age: null }

// 4. Keyof ilə Mapped Type
type Keys = keyof Person; // "name" | "age"
type PersonValues = { [P in Keys]: Person[P] };
const values: PersonValues = { name: "Alice", age: 30 };
console.log(values); // Çıxış: { name: "Alice", age: 30 }

// 5. Utility Types ilə Mapped Type
type PartialPerson = Partial<Person>; // { name?: string; age?: number }
const partial: PartialPerson = { name: "Alice" };
console.log(partial); // Çıxış: { name: "Alice" }

type ReadonlyPersonUtility = Readonly<Person>;
const readonlyPerson: ReadonlyPersonUtility = { name: "Bob", age: 25 };
// readonlyPerson.name = "Alice"; // Səhv: name yalnız oxuna biləndir
console.log(readonlyPerson); // Çıxış: { name: "Bob", age: 25 }

// 6. Union Tipləri ilə Mapped Type
type KeysUnion = "id" | "name";
type UnionMapped = { [P in KeysUnion]: string };
const unionMapped: UnionMapped = { id: "P001", name: "Laptop" };
console.log(unionMapped); // Çıxış: { id: "P001", name: "Laptop" }

// 7. Mapped Type ilə Funksiya
function mapProperties<T>(obj: T): { [P in keyof T]: string } {
  const result = {} as { [P in keyof T]: string };
  for (const key in obj) {
    result[key] = String(obj[key]);
  }
  return result;
}
const mapped = mapProperties({ name: "Alice", age: 30 });
console.log(mapped); // Çıxış: { name: "Alice", age: "30" }

// Sadə mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
}
type OptionalProduct = { [P in keyof Product]?: Product[P] };
class ProductStore {
  products: OptionalProduct[] = [];
  add(product: OptionalProduct): void {
    this.products.push(product);
  }
  getById(id: string): OptionalProduct | undefined {
    return this.products.find(p => p.id === id);
  }
}
const store = new ProductStore();
store.add({ id: "P001", name: "Laptop" }); // price opsionaldır
store.add({ id: "P002", price: 999 });
console.log(store.getById("P001")); // Çıxış: { id: "P001", name: "Laptop" }

// Şərti mapped type ilə funksiya
type StringFields<T> = { [P in keyof T]: T[P] extends string ? T[P] : never };
function getStringFields<T>(obj: T): StringFields<T> {
  const result = {} as StringFields<T>;
  for (const key in obj) {
    result[key] = (typeof obj[key] === "string" ? obj[key] : null) as any;
  }
  return result;
}
const product: Product = { id: "P003", name: "Mouse", price: 25 };
const stringFields = getStringFields(product);
console.log(stringFields); // Çıxış: { id: "P003", name: "Mouse", price: null }

